import { SUPABASE_EDGE_BASE_URL, getSupabase } from "../../database/supabase";
import { useState } from "react";
import React from "react";

const EDGE_FUNCTION_URL = `${SUPABASE_EDGE_BASE_URL}`;

const box = (children: React.ReactNode) => (
  <div
    style={{
      background: "#0f172a",
      color: "#e5e7eb",
      padding: 16,
      borderRadius: 8,
      border: "1px solid #334155",
      fontFamily: "JetBrains Mono, Menlo, monospace",
      marginBottom: 16,
      whiteSpace: "pre-wrap",
    }}
  >
    {children}
  </div>
);

export default function AdminEdgeTest() {
  const [name, setName] = useState("Abdul");
  const [status, setStatus] = useState<string | null>(null);
  const [response, setResponse] = useState<any>(null);
  const [tokenPreview, setTokenPreview] = useState<string | null>(null);

  async function callEdge() {
    setStatus("Getting session...");

    const supabase = await getSupabase(); // ✅ THIS is your dynamic key

    const { data: sessionData } = await supabase.auth.getSession();
    const token = sessionData?.session?.access_token;

    console.log(token);

    if (!token) {
      setStatus("❌ NOT LOGGED IN — no token available");
      return;
    }

    setTokenPreview(token.slice(0, 40) + "...");

    try {
      setStatus("Calling Edge Function...");

      const res = await fetch(EDGE_FUNCTION_URL, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${token}`,
        },
        body: JSON.stringify({ name }),
      });

      const json = await res.json();
      setResponse(json);

      if (!res.ok) {
        setStatus(`❌ BLOCKED (status ${res.status})`);
      } else {
        setStatus("✅ SUCCESS — admin access confirmed");
      }
    } catch (err: any) {
      setStatus("💥 NETWORK ERROR");
      setResponse({ error: String(err) });
    }
  }

  return (
    <div
      style={{
        fontFamily:
          "Inter, -apple-system, system-ui, Segoe UI, Roboto, sans-serif",
        padding: 32,
        background: "#0b1220",
        color: "#e5e7eb",
        minHeight: "100vh",
      }}
    >
      <h1 style={{ color: "#facc15" }}>🧪 Supabase Admin Edge Test</h1>

      {box(
        <>
          <strong>1) Enter a name</strong>
          <br />
          <input
            value={name}
            onChange={(e) => setName(e.target.value)}
            style={{
              marginTop: 8,
              padding: 8,
              width: 300,
              background: "#020617",
              color: "#e5e7eb",
              border: "1px solid #334155",
              borderRadius: 6,
            }}
          />
        </>
      )}

      {box(
        <>
          <strong>2) Call your Edge Function</strong>
          <br />
          <button
            onClick={callEdge}
            style={{
              marginTop: 8,
              padding: "8px 12px",
              background: "#facc15",
              color: "#020617",
              border: "none",
              borderRadius: 6,
              fontWeight: 600,
            }}
          >
            CALL HELLO-ADMIN
          </button>
        </>
      )}

      {status &&
        box(
          <>
            <strong>Status:</strong>
            <br />
            {status}
          </>
        )}

      {tokenPreview &&
        box(
          <>
            <strong>JWT Preview (client side):</strong>
            <br />
            {tokenPreview}
          </>
        )}

      {response &&
        box(
          <>
            <strong>Edge Response:</strong>
            <br />
            {JSON.stringify(response, null, 2)}
          </>
        )}
    </div>
  );
}